  flex-direction: column;
  align-items: center;
  justify-content: center;
  width: 100%;
}

.adapted-value-container {
  display: flex;
    align-items: center;
  flex-direction: column;
  align-items: center; /* Alinha o conteúdo à direita */
  justify-content: center;
  width: 100%;
