body {
  background: linear-gradient(135deg, #012126, #000d12, #001b02);
  background-size: 400% 400%;
  animation: gradientBG 15s ease infinite;
  font-family: Arial, sans-serif;

}

@keyframes gradientBG {
  0% {
    background-position: 0% 50%;
  }
  50% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0% 50%;
  }
}

options.css:
* {
  box-sizing: border-box;
  font-family: Inter, Arial, sans-serif;
}

.cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(340px, 1fr));
  gap: 10px;
  width: 100%;
  padding: 8px;
}

.cert-card {
  border-radius: 18px;
  background: linear-gradient(180deg, rgba(26, 69, 77, 0.96), rgba(7, 21, 22, 0.96));
  border: 1px solid rgba(255,255,255,0.08);
  box-shadow: 0 8px 24px rgba(73, 73, 73, 0.35);
  color: #e5e7eb;
  padding: 18px;
}

.cert-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 12px;
  margin-bottom: 18px;
}

.cert-title {
  font-size: 24px;
  font-weight: 700;
  line-height: 1.1;
}

.cert-subtitle {
  margin-top: 4px;
  color: #9ca3af;
  font-size: 10px;
}

.badge {
  padding: 8px 14px;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 700;
  border: 1px solid rgba(255,255,255,0.1);
  background: rgba(255,255,255,0.05);
  color: #e5e7eb;
  white-space: nowrap;
}

.badge-ok {
  color: #8af686;
  background: rgba(102, 167, 126, 0.16);
}

.badge-warning {
  color: #fde68a;
  background: rgba(245,158,11,0.16);
}

.badge-critical {
  color: #451c1c;
  background: rgba(255, 22, 22, 0.846);
}

.timeline-labels {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
  color: #9ca3af;
}

.timeline-labels.top {
  margin-bottom: 5px;
  text-transform: uppercase;
}

.timeline-labels.bottom {
  margin-top: 1px;
  color: #e5e7eb;
  font-weight: 600;
}

.timeline {
  position: relative;
  height: 36px;
  display: flex;
  align-items: center;
}

.timeline-base {
  width: 100%;
  height: 10px;
  border-radius: 999px;
  background: rgba(255,255,255,0.08);
  position: absolute;
}

.timeline-progress {
  height: 10px;
  border-radius: 999px;
  position: absolute;
  left: 0;
}

.timeline-point {
  position: absolute;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  border: 3px solid #111827;
  z-index: 2;
}

.timeline-point.start {
  left: 0%;
  background: #60a5fa;
}

.timeline-point.now {
  background: #f8fafc;
  box-shadow: 0 0 0 6px rgba(255,255,255,0.08);
}

.timeline-point.end {
  left: 100%;
  background: #a78bfa;
}

.metrics {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 5px;
  margin-top: 12px;
}

.metric {
  padding: 14px;
  border-radius: 14px;
  background: rgba(255,255,255,0.04);
  border: 1px solid rgba(255,255,255,0.05);
}

.metric-label {
  display: block;
  font-size: 10px;
  color: #9ca3af;
  margin-bottom: 8px;
  text-transform: uppercase;
}

.metric strong {
  font-size: 16px;
  color: #f9fafb;
}





.detail-label {
  font-size: 10px;
  color: #9ca3af;
  margin-bottom: 8px;
  text-transform: uppercase;
}

.details {
  margin-top: 4px;
  display: flex;
  justify-content: center;
}

