options.onRender:
function normalizeText(text) {
  return String(text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function getSeriesList() {
  return htmlGraphics?.data?.series || data?.series || [];
}

function getLastFieldValue(field) {
  if (!field) return null;

  if (field.state?.calcs?.last !== undefined && field.state?.calcs?.last !== null) {
    return field.state.calcs.last;
  }

  if (field.values?.buffer?.length) {
    return field.values.buffer[field.values.buffer.length - 1];
  }

  if (Array.isArray(field.values) && field.values.length) {
    return field.values[field.values.length - 1];
  }

  return null;
}

function getValueField(series) {
  if (!series?.fields?.length) return null;

  for (const field of series.fields) {
    const fieldName = normalizeText(field.name);
    if (fieldName === "value" || fieldName === "last" || fieldName === "valor") {
      return field;
    }
  }

  return series.fields[1] || series.fields[0] || null;
}

function splitMetricName(seriesName) {
  const raw = String(seriesName || "").trim();
  const match = raw.match(/^(.*?)\s*-\s*(.+)$/);

  if (!match) {
    return { certName: "", metricName: "" };
  }

  return {
    certName: match[1].trim(),
    metricName: match[2].trim()
  };
}

function normalizeCertName(certName) {
  return String(certName || "").replace(/\s+/g, " ").trim();
}

function isValidCertName(certName) {
  const raw = normalizeCertName(certName);
  const normalized = normalizeText(raw);

  if (!raw) return false;
  if (!normalized.endsWith(".pfx")) return false;
  if (normalized === ".pfx") return false;

  if (
    normalized.includes("value") ||
    normalized.includes("time") ||
    normalized.includes("series")
  ) {
    return false;
  }

  return true;
}

function mapMetricKey(metricName) {
  const m = normalizeText(metricName);

  if (m.includes("dias restantes do certificado")) return "remainingDays";
  if (m.includes("tempo desde emissao")) return "elapsedDays";
  if (m.includes("inicio da validade")) return "startDate";
  if (m.includes("fim da validade")) return "endDate";
  if (m === "status" || m.includes("status")) return "status";
  if (m === "tipo" || m.includes("tipo")) return "tipo";

  return null;
}

function buildCertificates() {
  const certificates = {};

  for (const series of getSeriesList()) {
    const { certName, metricName } = splitMetricName(series.name);
    const normalizedCertName = normalizeCertName(certName);
    const metricKey = mapMetricKey(metricName);

    if (!metricKey || !isValidCertName(normalizedCertName)) {
      continue;
    }

    if (!certificates[normalizedCertName]) {
      certificates[normalizedCertName] = {
        certName: normalizedCertName,
        remainingDays: null,
        elapsedDays: null,
        startDate: null,
        endDate: null,
        status: null,
        tipo: null
      };
    }

    const field = getValueField(series);
    const value = getLastFieldValue(field);

    certificates[normalizedCertName][metricKey] = value;
  }

  return Object.values(certificates).filter(cert => {
    return (
      cert.certName &&
      isValidCertName(cert.certName) &&
      (
        cert.remainingDays !== null ||
        cert.elapsedDays !== null ||
        cert.startDate !== null ||
        cert.endDate !== null ||
        cert.status !== null ||
        cert.tipo !== null
      )
    );
  });
}

function formatNumber(value, suffix = "") {
  if (value === null || value === undefined || value === "" || Number.isNaN(Number(value))) {
    return "--";
  }
  return `${Number(value)}${suffix}`;
}

function formatText(value) {
  if (value === null || value === undefined || value === "") {
    return "--";
  }
  return String(value);
}

function formatDate(value) {
  if (value === null || value === undefined || value === "") return "--";

  const asNumber = Number(value);
  if (!Number.isNaN(asNumber) && String(value).trim() !== "") {
    const epochDate = new Date(asNumber * 1000);
    if (!Number.isNaN(epochDate.getTime())) {
      return epochDate.toLocaleDateString("pt-BR");
    }
  }

  const date = new Date(value);
  if (!Number.isNaN(date.getTime())) {
    return date.toLocaleDateString("pt-BR");
  }

  return String(value);
}

function getBadgeInfo(statusText, remainingDays) {
  const status = normalizeText(statusText);
  const remaining = Number(remainingDays);

  if (
    status.includes("expired") ||
    status.includes("expirado") ||
    status.includes("erro") ||
    (!Number.isNaN(remaining) && remaining < 0)
  ) {
    return { text: "Crítico", className: "badge badge-critical" };
  }

  if (!Number.isNaN(remaining) && remaining <= 30) {
    return { text: "Atenção", className: "badge badge-warning" };
  }

  return { text: "Saudável", className: "badge badge-ok" };
}

function getProgressInfo(elapsedDays, totalDays) {
  const elapsed = Number(elapsedDays);
  const total = Number(totalDays);

  if (Number.isNaN(elapsed) || Number.isNaN(total) || total <= 0) {
    return { percent: 0, color: "#22c55e" };
  }

  let percent = (elapsed / total) * 100;
  if (percent < 0) percent = 0;
  if (percent > 100) percent = 100;

  let color = "#22c55e";
  if (percent >= 90) {
    color = "#ef4444";
  } else if (percent >= 70) {
    color = "#f59e0b";
  }

  return { percent, color };
}

function renderCard(cert) {
  let totalDays = null;
  if (cert.elapsedDays !== null && cert.remainingDays !== null) {
    totalDays = Number(cert.elapsedDays) + Number(cert.remainingDays);
  }

  let usedPercent = null;
  if (totalDays !== null && Number(totalDays) > 0 && cert.elapsedDays !== null) {
    usedPercent = (Number(cert.elapsedDays) / Number(totalDays)) * 100;
  }

  const badge = getBadgeInfo(cert.status, cert.remainingDays);
  const progress = getProgressInfo(cert.elapsedDays, totalDays);
  const nowDate = new Date().toLocaleDateString("pt-BR");

  return `
    <div class="cert-card">
      <div class="cert-header">
        <div>
          <div class="cert-title">${formatText(cert.certName)}</div>
          <div class="cert-subtitle">Tempo de vida do certificado</div>
        </div>
        <div class="${badge.className}">${badge.text}</div>
      </div>

      <div class="timeline-labels top">
        <span>Início</span>
        <span>Agora</span>
        <span>Expiração</span>
      </div>

      <div class="timeline">
        <div class="timeline-base"></div>
        <div class="timeline-progress" style="width:${progress.percent}%; background:${progress.color};"></div>
        <div class="timeline-point start"></div>
        <div class="timeline-point now" style="left:${progress.percent}%;"></div>
        <div class="timeline-point end"></div>
      </div>

      <div class="timeline-labels bottom">
        <span>${formatDate(cert.startDate)}</span>
        <span>${nowDate}</span>
        <span>${formatDate(cert.endDate)}</span>
      </div>

      <div class="metrics">
        <div class="metric">
          <span class="metric-label">Vida consumida</span>
          <strong>${usedPercent === null ? "--" : usedPercent.toFixed(1) + "%"}</strong>
        </div>
        <div class="metric">
          <span class="metric-label">Dias restantes</span>
          <strong>${formatNumber(cert.remainingDays, " dias")}</strong>
        </div>
        <div class="metric">
          <span class="metric-label">Tempo desde emissão</span>
          <strong>${formatNumber(cert.elapsedDays, " dias")}</strong>
        </div>
        <div class="metric">
          <span class="metric-label">Vida total</span>
          <strong>${formatNumber(totalDays, " dias")}</strong>
        </div>
      </div>

      <div class="details">
        <div class="detail">
          <span class="detail-label">Tipo = </span>
          <span class="detail-value">${formatText(cert.tipo)}</span>
        </div>
      </div>
    </div>
  `;
}

function render() {
  const container = htmlNode.querySelector("#cardsContainer");
  if (!container) return;

  const certs = buildCertificates();

  if (!certs.length) {
    container.innerHTML = `<div class="cert-card">Nenhum certificado encontrado nas séries do painel.</div>`;
    return;
  }

  container.innerHTML = certs
    .sort((a, b) => a.certName.localeCompare(b.certName))
    .map(renderCard)
    .join("");

  console.log("Séries recebidas:", getSeriesList().map(s => s.name));
  console.log("Certificados montados:", certs);
}

